sql:
SELECT MAX(humidity_value) AS max_humidity, MIN(humidity_value) AS min_humidity
FROM humidity
WHERE sensor_id = 1;

SELECT MAX(wind_speed_value) AS max_wind_speed, timestamp
FROM wind_speed
WHERE sensor_id = 0;

SELECT temperature, humidity, wind_speed
FROM weather_forecasts
WHERE forecast_id = 0;

